import React, { Component, useState } from "react";
import Slider from "react-slick";
import './SliderStyles.css';
import ATM from './ImagesCollection/ATM.png';
import ATMMobile from './ImagesCollection/ATMMobile.png';
import ORU from './ImagesCollection/ORU.png';
import ORUMobile from './ImagesCollection/ORUMobile.png';
import ARG from './ImagesCollection/ARG.png';
import ARGMobile from './ImagesCollection/ARGMobile.png';
import VND from './ImagesCollection/VND.png';
import VNDMobile from './ImagesCollection/VNDMobile.png';
import RightArrow from './ImagesCollection/ArrowRight.svg';
import LeftArrow from './ImagesCollection/ArrowLeft.svg';
import MediaQuery from 'react-responsive'

function NextArrow(props) {
    const { className, style, onClick } = props;
    return (
        <div
        className='rightArrow'
        onClick={onClick}
      ><img src={RightArrow } className='Arrow'/> </div>
    );
  }
  
  function PrevArrow(props) {
    const { className, style, onClick } = props;
    return (
      <div
        className='LeftArrow'
        onClick={onClick}
      ><img src={LeftArrow} className='Arrow'/> </div>
    );
  }

export default class SlideShow extends Component {
    
  render() {
    
        const settings = {
          dots: false,
          infinite: true,
          speed: 500,
          slidesToShow: 1,
          slidesToScroll: 1,
          nextArrow: <NextArrow />,
          prevArrow: <PrevArrow />
        };
        return (
          <div className="SliderWrapper">
            <Slider {...settings}>
              <div className="Slides">
              <MediaQuery maxWidth={480}>
              <a href="https://atmosprotocol.com/"  target="_blank">
                <img src={ATMMobile} className="SlideImages"/>
                </a>
                </MediaQuery>
              <MediaQuery minWidth={481}>
              <a href="https://atmosprotocol.com/"  target="_blank">
                <img src={ATM} className="SlideImages"/>
                </a>
                </MediaQuery>
                <a href="https://atmosprotocol.com/" className="SlideLink" target="_blank">Atmos Protocol</a>
              </div>

              <div className="Slides">
              <MediaQuery maxWidth={480}>
              <a href="https://orcusfinance.io/"  target="_blank">
                <img src={ORUMobile} className="SlideImages"/>
                </a>
                </MediaQuery>
              <MediaQuery minWidth={481}>
              <a href="https://orcusfinance.io/" target="_blank">
                <img src={ORU} className="SlideImages"/>
                </a>
                </MediaQuery>
                <a href="https://orcusfinance.io/" className="SlideLink" target="_blank">Orcus Finance</a>
              </div>

              <div className="Slides">
              <MediaQuery maxWidth={480}>
              <a href="https://www.argano.io/" target="_blank">
                <img src={ARGMobile} className="SlideImages"/>
                </a>
                </MediaQuery>
              <MediaQuery minWidth={481}>
              <a href="https://www.argano.io/" target="_blank">
                <img src={ARG} className="SlideImages"/>
                </a>
                </MediaQuery>
                <a href="https://www.argano.io/" className="SlideLink" target="_blank">Argano</a>
              </div>

              <div className="Slides">
              <MediaQuery maxWidth={480}>
              <a href="https://vineyardao.com/" target="_blank">
                <img src={VNDMobile} className="SlideImages"/>
                </a>
                </MediaQuery>
              <MediaQuery minWidth={481}>
              <a href="https://vineyardao.com/" target="_blank">
                <img src={VND} className="SlideImages"/>
                </a>
                </MediaQuery>
                <a href="https://vineyardao.com/" className="SlideLink" target="_blank">Vineyard DAO</a>
              </div>
              
            </Slider>
          </div>
        );
      }
    }